import requests

class OPAPolicyEngine:
    """Delegates policy evaluation to an Open Policy Agent server."""

    def __init__(self, opa_url: str = "http://localhost:8181"):
        self.opa_url = opa_url

    def evaluate(self, action, tool_name, inputs, context):
        payload = {
            "input": {
                "action": action,
                "tool": tool_name,
                "user": {
                    "id": context.user_id,
                    "jurisdiction": context.jurisdiction
                },
                "data_classifications": context.data_classifications,
                "agent_id": context.agent_id
            }
        }
        resp = requests.post(
            f"{self.opa_url}/v1/data/agentic/compliance/allow",
            json=payload,
            timeout=0.5  # 500ms budget
        )
        resp.raise_for_status()
        result = resp.json()

        if not result.get("result", {}).get("allow", False):
            violations = result.get("result", {}).get("violations", [])
            return PolicyDecision.DENY, violations

        flags = result.get("result", {}).get("flags", [])
        return PolicyDecision.ALLOW, flags

